{
  "root_causes": [
    {
      "type": "Administrative shutdown on R2",
      "cause": "R2 Serial0/1/0 is configured shutdown (administratively down), so the interface is down on R2.",
      "evidence": [
        "R2 running-config: interfaces -> Serial -> name: \"0/1/0\" contains \"shutdown\": [ null ]",
        "R2 running-config: interfaces -> Serial -> name: \"0/1/0\" ip address primary: \"10.0.0.2\" (shows interface exists but is shut)"
      ],
      "confidence": 0.95
    },
    {
      "type": "Remote-side admin down causing local lower-layer-down",
      "cause": "R1 Serial0/1/0 is administratively up (no shutdown) but shows operational 'lower-layer-down' because the far end (R2) is administratively down, preventing link/up of the physical/line protocol.",
      "evidence": [
        "R1 running-config: interfaces -> Serial -> name: \"0/1/0\" has IP address primary \"10.0.0.1\" and no \"shutdown\" stanza (interface is admin up)",
        "Topology/run-config evidence: R1 Serial0/1/0 10.0.0.1/30 <-> R2 Serial0/1/0 10.0.0.2/30 (interfaces expected to be a point-to-point link)",
        "Alert description: R1 oper -> lower-layer-down, admin up; R2 oper -> down, admin -> down (matches configurations above)"
      ],
      "confidence": 0.9
    }
  ],
  "missing_info": []
}

{
  "intent": "check_and_fix",
  "intent_description": "R2 Serial0/1/0 is administratively down causing R1 Serial0/1/0 to report lower-layer-down; goal is to restore the point-to-point link so both interfaces are administratively and operationally up.",
  "target": "R1,R2",
  "needs_fix": true,
  "plan": {
    "problem": "R2 Serial0/1/0 is administratively shutdown, preventing link with R1 and causing R1 oper state lower-layer-down.",
    "fix_summary": "Bring R2 Serial0/1/0 administratively up (remove shutdown) so the serial link with R1 can achieve up/up.",
    "plan_steps": [
      {
        "id": 1,
        "device": "router2",
        "action": "set_interface_admin_up",
        "target": "Serial0/1/0",
        "parameters": [
          "no shutdown"
